const STORIES=[
  {id:1,t:"Сотворение Адама",ar:"خلق آدم",s:"2:30-39",sum:"Аллах создал первого человека — Адама — из глины и вдохнул в него душу. Он научил Адама именам всех вещей и повелел ангелам поклониться ему. Все поклонились, кроме Иблиса (шайтана), который отказался из гордости: «Я лучше, Ты создал меня из огня, а его — из глины.» Адам и Хавва (Ева) жили в Раю, но нарушили запрет и были спущены на землю. Адам покаялся и был прощён — так началась история человечества.",les:["Покаяние принимается — Аллах прощает","Гордыня — путь к падению","Человек — наместник Аллаха на земле"],ay:["2:30","2:34","7:11-25","15:28-42"]},
  {id:2,t:"Нух и потоп",ar:"نوح والطوفان",s:"Худ 11, Нух 71",sum:"Пророк Нух (Ной) 950 лет терпеливо призывал свой народ к единобожию, но лишь немногие уверовали. Люди насмехались и поклонялись идолам. Аллах повелел Нуху построить ковчег. Когда корабль был готов, хлынул великий потоп. Нух взял на борт верующих и по паре от каждого вида живых существ. Даже его собственный сын отказался подняться на корабль и погиб в волнах. Вода покрыла всю землю, и ковчег пристал к горе Джуди.",les:["Терпение в призыве — 950 лет!","Спасение через веру и послушание Аллаху","Родственные связи не спасают без веры"],ay:["11:25-49","71:1-28","23:23-30"]},
  {id:3,t:"Ибрахим и Кааба",ar:"إبراهيم والكعبة",s:"2:124-131",sum:"Ибрахим (Авраам) — «Халиль Аллах» (Друг Аллаха). Юношей он осознал ложность идолов своего отца Азара и разбил их, оставив лишь самого большого. Народ бросил его в огонь, но Аллах сделал пламя прохладным. Аллах испытал его приказом принести в жертву сына Исмаила — оба покорились воле Аллаха, и Аллах заменил жертву бараном (отсюда Курбан-байрам). Вместе с Исмаилом Ибрахим построил Каабу в Мекке и молил: «Господи, сделай этот город безопасным!»",les:["Упование на Аллаха превыше всего","Жертвенность и покорность Аллаху","Ибрахим — отец пророков"],ay:["2:124-131","37:83-113","21:51-71","14:35-41"]},
  {id:4,t:"Юсуф — прекраснейшая история",ar:"يوسف",s:"Юсуф 12",sum:"Юсуф (Иосиф) — сын Якуба, один из 12 братьев. Аллах одарил его красотой и пророческими снами. Братья из зависти бросили мальчика в колодец и сказали отцу, что его съел волк. Юсуф был продан в рабство в Египет. Жена вельможи Зулейха соблазняла его, но он устоял и был заключён в тюрьму. Там он толковал сны, и, предсказав засуху для фараона, был назначен хранителем запасов — фактически правителем Египта. Когда братья пришли за зерном, Юсуф узнал их и простил. Семья воссоединилась.",les:["Терпение вознаграждается — от колодца до трона","Прощение — высшая сила","Аллах управляет всем, даже через трудности"],ay:["12:1-111"]},
  {id:5,t:"Муса и Фараон",ar:"موسى وفرعون",s:"Аль-Касас 28",sum:"Младенца Мусу (Моисея) мать положила в корзину и отправила по реке Нил — спасая от приказа Фараона убивать мальчиков сынов Исраиля. Корзину нашла жена Фараона и воспитала Мусу. Взрослым Муса получил пророчество и посох, творящий чудеса. Он пришёл к Фараону с призывом отпустить народ, показал 9 знамений. Фараон отказался. Тогда Аллах рассёк море — народ Мусы прошёл, а Фараон с войском утонул. Позже Муса получил Тору на горе Синай.",les:["Аллах защищает слабых","Тирания обречена на гибель","Терпение и мужество пророка"],ay:["20:9-98","28:1-43","26:10-68","7:103-137"]},
  {id:6,t:"Давуд и Сулейман",ar:"داود وسليمان",s:"21:78-82",sum:"Пророк Давуд (Давид) — мужественный юноша, победивший великана Джалута (Голиафа) с помощью пращи и веры в Аллаха. Аллах дал ему царство, мудрость, прекрасный голос для чтения Забура (Псалмов) и умение размягчать железо. Его сын Сулейман (Соломон) получил ещё большие дары: власть над ветром, понимание языка животных и птиц, подчинение джиннов. Сулейман построил величественный Храм. Муравей, удод и царица Савская — знаменитые эпизоды его истории.",les:["Мудрость — дар Аллаха","Благодарность за каждую милость","Сила и царство — от Аллаха"],ay:["21:78-82","27:15-44","34:10-14","38:30-40"]},
  {id:7,t:"Иса ибн Марьям",ar:"عيسى ابن مريم",s:"Марьям 19:16-36",sum:"Марьям (Мария) — единственная женщина, названная по имени в Коране (целая сура «Марьям»). Выросла при храме под опекой Закарии. Ангел Джибриль принёс ей весть о рождении сына без отца — по воле Аллаха. Иса (Иисус) заговорил в колыбели, защитив мать от обвинений. Аллах дал ему чудеса: исцеление слепых и прокажённых, воскрешение мёртвых. Коран утверждает: Иса — пророк и раб Аллаха, но не Бог и не сын Бога. Он был вознесён живым на небо.",les:["Иса — великий пророк ислама","Чудо рождения — знамение Аллаха","Марьям — образец благочестия"],ay:["3:42-59","19:16-36","5:110-118"]},
  {id:8,t:"Исра и Мирадж",ar:"الإسراء والمعراج",s:"Аль-Исра 17:1",sum:"В труднейший год жизни Пророка ﷺ (после смерти жены Хадиджи и дяди Абу Талиба) Аллах подарил ему ночное путешествие. За одну ночь Джибриль перенёс Мухаммада ﷺ на крылатом Бураке из Мекки в Иерусалим (Исра). Там он возглавил молитву всех пророков в Масджид аль-Акса. Затем вознёсся через семь небес (Мирадж), где встретил Адама, Ибрахима, Мусу, Ису. На последнем уровне получил повеление о пятикратной молитве — главном столпе ислама после шахады.",les:["Пятикратная молитва — дар с небес","Все пророки — одна цепь, один Бог","После трудностей Аллах посылает свет"],ay:["17:1","53:1-18"]},
  {id:9,t:"Откровение Корана",ar:"نزول القرآن",s:"Аль-Алак 96:1-5",sum:"В 610 году н.э. Мухаммаду ﷺ было 40 лет. Он уединился в пещере Хира на горе Нур для размышлений. Ангел Джибриль явился и сжал его, повелев: «Читай!» (Икра'). Мухаммад ﷺ ответил: «Я не умею читать.» Джибриль повторил трижды и произнёс первые аяты: «Читай во имя Господа твоего, Который сотворил...» Так началось ниспослание Корана, продолжавшееся 23 года — в Мекке (13 лет) и Медине (10 лет). 114 сур, 6236 аятов — послание для всего человечества.",les:["Знание — первая заповедь Корана","23 года терпения и труда","Коран — завершение всех Писаний"],ay:["96:1-5","97:1-5","2:185","17:106"]},
];

